import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {

    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        if let url = userActivity.webpageURL {
            self.handle(url)
        }
        return true
    }

    private func handle(_ url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false),
              let scheme = components.scheme,
              let path = components.path else { return }

        switch (scheme, path) {
        case ("https", "profile/"):
            if let id = components.queryItems?.first(where: { $0.key == "id" })?.value {
                let profileVC = ProfileViewController()
                profileVC.id = Int(id)!
                self.navigationController?.pushViewController(profileVC, animated: true)
            }
        case ("https", "payment/confirm"):
            let paymentConfirmVC = PaymentConfirmViewController()
            self.navigationController?.pushViewController(paymentConfirmVC, animated: true)
        case ("https", "admin/settings"):
            let adminSettingsVC = AdminSettingsViewController()
            self.navigationController?.pushViewController(adminSettingsVC, animated: true)
        default:
            break
        }
    }
}